    "correspondence.field_link_transmittal": "Transmitere",
    "correspondence.hint_date_received_incoming": "Când a ajuns la dvs. (data cheie pentru corespondența de intrare).",
    "correspondence.hint_date_received_outgoing": "Opțional - când destinatarul a confirmat primirea.",
