    "payportal.back_to_app": "Înapoi la OpenConstructionERP",
    "payportal.signin_title": "Conectați-vă la portalul subcontractantului",
    "payportal.signin_prompt": "Deschideți linkul securizat din e-mailul de invitație pentru a continua.",
